# Generated by openai (gpt-5.4)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    options {
        timestamps()
        disableConcurrentBuilds()
        buildDiscarder(logRotator(numToKeepStr: '30'))
        timeout(time: 90, unit: 'MINUTES')
    }

    parameters {
        text(
            name: 'ARTIFACT_URLS',
            defaultValue: '',
            description: 'One artifact URL per line. Supports HTTP/HTTPS/S3-style URLs if accessible by curl.'
        )
        string(
            name: 'DEPLOY_PATH',
            defaultValue: '/opt/app/releases',
            description: 'Target directory on production servers'
        )
        text(
            name: 'PROD_SERVERS',
            defaultValue: 'prod-app-01\nprod-app-02',
            description: 'One production server per line'
        )
        string(
            name: 'SSH_CREDENTIALS_ID',
            defaultValue: 'prod-ssh',
            description: 'Jenkins SSH credentials ID for production servers'
        )
        string(
            name: 'SSH_USER',
            defaultValue: 'deploy',
            description: 'SSH user for production servers'
        )
        string(
            name: 'HTTP_CREDENTIALS_ID',
            defaultValue: '',
            description: 'Optional Jenkins username/password credentials ID for artifact downloads'
        )
        booleanParam(
            name: 'CLEAN_REMOTE_DIR',
            defaultValue: false,
            description: 'Clean target release directory before upload'
        )
        booleanParam(
            name: 'UNPACK_ARCHIVES',
            defaultValue: true,
            description: 'Unpack .zip/.tar/.tar.gz/.tgz artifacts on remote servers after upload'
        )
        booleanParam(
            name: 'VERIFY_CHECKSUMS',
            defaultValue: false,
            description: 'If true, also try to download <artifact>.sha256 and verify locally'
        )
    }

    environment {
        LOCAL_DOWNLOAD_DIR = "${WORKSPACE}/downloads"
        LOCAL_MANIFEST = "${WORKSPACE}/artifact-manifest.txt"
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    def artifactUrls = params.ARTIFACT_URLS
                        .split('\n')
                        .collect { it.trim() }
                        .findAll { it }

                    def prodServers = params.PROD_SERVERS
                        .split('\n')
                        .collect { it.trim() }
                        .findAll { it }

                    if (artifactUrls.isEmpty()) {
                        error('ARTIFACT_URLS must contain at least one URL')
                    }

                    if (prodServers.isEmpty()) {
                        error('PROD_SERVERS must contain at least one server')
                    }

                    if (!params.DEPLOY_PATH?.trim()) {
                        error('DEPLOY_PATH must not be empty')
                    }

                    writeFile file: "${env.WORKSPACE}/artifact-urls.txt", text: artifactUrls.join('\n') + '\n'
                    writeFile file: "${env.WORKSPACE}/prod-servers.txt", text: prodServers.join('\n') + '\n'
                }
            }
        }

        stage('Prepare Workspace') {
            steps {
                sh '''
                    set -euo pipefail
                    rm -rf "$LOCAL_DOWNLOAD_DIR"
                    mkdir -p "$LOCAL_DOWNLOAD_DIR"
                    : > "$LOCAL_MANIFEST"
                '''
            }
        }

        stage('Download Artifacts') {
            steps {
                script {
                    def urls = readFile("${env.WORKSPACE}/artifact-urls.txt")
                        .split('\n')
                        .collect { it.trim() }
                        .findAll { it }

                    if (params.HTTP_CREDENTIALS_ID?.trim()) {
                        withCredentials([usernamePassword(
                            credentialsId: params.HTTP_CREDENTIALS_ID,
                            usernameVariable: 'HTTP_USER',
                            passwordVariable: 'HTTP_PASS'
                        )]) {
                            urls.eachWithIndex { url, idx ->
                                downloadArtifact(url, idx + 1, params.VERIFY_CHECKSUMS)
                            }
                        }
                    } else {
                        urls.eachWithIndex { url, idx ->
                            downloadArtifact(url, idx + 1, params.VERIFY_CHECKSUMS)
                        }
                    }
                }
            }
        }

        stage('Deploy to Production') {
            steps {
                script {
                    def servers = readFile("${env.WORKSPACE}/prod-servers.txt")
                        .split('\n')
                        .collect { it.trim() }
                        .findAll { it }

                    sshagent(credentials: [params.SSH_CREDENTIALS_ID]) {
                        servers.each { server ->
                            deployToServer(server)
                        }
                    }
                }
            }
        }
    }

    post {
        always {
            archiveArtifacts artifacts: 'artifact-manifest.txt', onlyIfSuccessful: false
            sh '''
                set +e
                rm -rf "$LOCAL_DOWNLOAD_DIR"
            '''
        }
    }
}

def downloadArtifact(String url, int index, boolean verifyChecksums) {
    def safeName = url.tokenize('/').last()
    if (!safeName || safeName.trim().isEmpty()) {
        safeName = "artifact-${index}"
    }

    safeName = safeName.replaceAll(/[?#].*$/, '')
    if (!safeName) {
        safeName = "artifact-${index}"
    }

    def targetFile = "${env.LOCAL_DOWNLOAD_DIR}/${index}-${safeName}"

    withEnv([
        "ARTIFACT_URL=${url}",
        "TARGET_FILE=${targetFile}",
        "VERIFY_SUM=${verifyChecksums ? 'true' : 'false'}"
    ]) {
        sh '''
            set -euo pipefail

            auth_args=()
            if [ -n "${HTTP_USER:-}" ] && [ -n "${HTTP_PASS:-}" ]; then
              auth_args=(-u "${HTTP_USER}:${HTTP_PASS}")
            fi

            echo "Downloading ${ARTIFACT_URL} -> ${TARGET_FILE}"
            curl -fL --retry 3 --connect-timeout 20 "${auth_args[@]}" -o "${TARGET_FILE}" "${ARTIFACT_URL}"

            if [ "${VERIFY_SUM}" = "true" ]; then
              checksum_url="${ARTIFACT_URL}.sha256"
              checksum_file="${TARGET_FILE}.sha256"
              if curl -fsSL --retry 2 --connect-timeout 20 "${auth_args[@]}" -o "${checksum_file}" "${checksum_url}"; then
                expected="$(awk '{print $1}' "${checksum_file}")"
                actual="$(sha256sum "${TARGET_FILE}" | awk '{print $1}')"
                [ "${expected}" = "${actual}" ]
              else
                echo "No checksum found at ${checksum_url}, failing because VERIFY_CHECKSUMS=true"
                exit 1
              fi
            fi

            size="$(wc -c < "${TARGET_FILE}" | tr -d ' ')"
            sha="$(sha256sum "${TARGET_FILE}" | awk '{print $1}')"
            printf "%s|%s|%s|%s\n" "${ARTIFACT_URL}" "${TARGET_FILE}" "${size}" "${sha}" >> "${LOCAL_MANIFEST}"
        '''
    }
}

def deployToServer(String server) {
    withEnv([
        "TARGET_SERVER=${server}",
        "REMOTE_BASE=${params.DEPLOY_PATH}",
        "REMOTE_USER=${params.SSH_USER}",
        "CLEAN_REMOTE=${params.CLEAN_REMOTE_DIR ? 'true' : 'false'}",
        "UNPACK_REMOTE=${params.UNPACK_ARCHIVES ? 'true' : 'false'}"
    ]) {
        sh '''
            set -euo pipefail

            release_id="$(date +%Y%m%d%H%M%S)"
            remote_release="${REMOTE_BASE}/${release_id}"

            ssh -o StrictHostKeyChecking=no "${REMOTE_USER}@${TARGET_SERVER}" "
              set -euo pipefail
              mkdir -p '${REMOTE_BASE}'
              mkdir -p '${remote_release}'
              if [ '${CLEAN_REMOTE}' = 'true' ]; then
                find '${remote_release}' -mindepth 1 -maxdepth 1 -exec rm -rf {} +
              fi
            "

            while IFS='|' read -r src_url local_file file_size file_sha; do
              [ -n \"${local_file}\" ] || continue
              base_name=\"$(basename "${local_file}")\"
              scp -o StrictHostKeyChecking=no "${local_file}" "${REMOTE_USER}@${TARGET_SERVER}:${remote_release}/${base_name}"
            done < "${LOCAL_MANIFEST}"

            ssh -o StrictHostKeyChecking=no "${REMOTE_USER}@${TARGET_SERVER}" "
              set -euo pipefail
              cd '${remote_release}'

              while IFS='|' read -r src_url local_file file_size file_sha; do
                [ -n \"\$local_file\" ] || continue
                base_name=\"\$(basename \"\$local_file\")\"
                if [ ! -f \"\$base_name\" ]; then
                  echo \"Missing uploaded artifact: \$base_name\"
                  exit 1
                fi

                actual_sha=\"\$(sha256sum \"\$base_name\" | awk '{print \\$1}')\"
                [ \"\$actual_sha\" = \"\$file_sha\" ]

                if [ '${UNPACK_REMOTE}' = 'true' ]; then
                  case \"\$base_name\" in
                    *.tar.gz|*.tgz)
                      tar -xzf \"\$base_name\"
                      ;;
                    *.tar)
                      tar -xf \"\$base_name\"
                      ;;
                    *.zip)
                      unzip -o \"\$base_name\"
                      ;;
                  esac
                fi
              done
            " < "${LOCAL_MANIFEST}"

            ssh -o StrictHostKeyChecking=no "${REMOTE_USER}@${TARGET_SERVER}" "
              set -euo pipefail
              ln -sfn '${remote_release}' '${REMOTE_BASE}/current'
            "
        '''
    }
}